SELECT COUNT(*)
FROM member
WHERE status = 'ACTIVE'



            AND (SYSDATE - created_at) <= #{conditionValue}



        AND (
            SELECT COUNT(*)
            FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}


        AND (
            SELECT COUNT(*)
            FROM review rv
            WHERE rv.member_id = member.member_id
        ) >= #{conditionValue}


        AND (
            SELECT NVL(SUM(r.total_price), 0)
            FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}

